". . . . G5 . . . . . . . E5 . . . . . . . C5 . . . . . . . D5 . . ."}]},"6":{"bpm":72,"loop":true,"gain":0.36,"swing":0.04,"tracks":[{"inst":"triangle","gain":0.46,"cutoff":520,"a":0.2,"d":1.6,"notes":"A2 . . . . . . . E3 . . . . . . . D3 . . . . . . . E3 . . . . . . ."},{"inst":"sine","gain":0.2,"cutoff":1500,"a":0.3,"d":1.8,"notes":"A4+C#5 . . . . . . . . . . . . . . . D4+F#4 . . . . . . . E4+G#4 . . . . . . ."},{"inst":"sine","gain":0.12,"cutoff":2600,"a":0.04,"d":0.5,"notes":". . A5 . . . E5 . . . C#5 . . . B4 . . . D5 . . . F#5 . . . E5 . . . A5 ."}]}}}; if (HLM[sim.act]) wd0.__play_music = { score: HLM[sim.act] }; wd0.music_mod = { brightness: ({ 1: 0.9, 2: 0.4, 3: 0.72, 4: 0.28 })[sim.act] || 0.7 } }
  const pdtX = Math.min(dt, 0.05)
  const mxX = ((wd0.mouse_x ?? 256) - 256) / 256
  const myX = ((wd0.mouse_y ?? 256) - 256) / 256
  const mdX = !!wd0.mouse_down
  const clickX = mdX && !HX.pmd
  const capX = (text, kind) => { if (typeof window !== 'undefined' && HX.capd !== text) { HX.capd = text; window.dispatchEvent(new CustomEvent('cafe:caption', { detail: { text, kind } })) } }
  const CHNAMES = ['', 'CHAPTER I \u2014 THE VALLEY', 'CHAPTER II \u2014 THE DROWNED MOON', 'CHAPTER III \u2014 THE BEARER', 'CHAPTER IV — THE FIRST LIGHT', 'CHAPTER V — THE QUORUM', 'CHAPTER VI — THE CHORUS']

  // ── chapter navigation: bottom corners, unlocked chapters only ──
  let navX = false
  if (clickX && myX > 0.65) {
    if (mxX < -0.45 && sim.act > 1) { sim.goChapter(sim.act - 1); HX.capd = ''; navX = true; capX(CHNAMES[sim.act], 'hint') }
    else if (mxX > 0.45 && sim.chapterUnlocked(sim.act + 1)) { sim.goChapter(sim.act + 1); HX.capd = ''; navX = true; capX(CHNAMES[sim.act], 'hint') }
  }

  if (sim.act === 1) {

    try {
      const wd = sim.worldData
      if (!wd.__hel || wd.__hel.v !== 2) wd.__hel = { v: 2, sx: 150, sy: 120, phase: 0, lx: -1, ly: -1, glow: 0 }
      const S = wd.__hel
      const pdt = Math.min(dt, 0.05)
      const HORIZON = 336

      const md = wd.mouse_down, mx = wd.mouse_x, my = wd.mouse_y
      const aspw = 1
      // HOVER carries the sun — no press needed; the light lives at your cursor
      if (typeof mx === 'number' && (mx !== S.lx || my !== S.ly)) {
        S.lx = mx; S.ly = my
        S.sx = Math.max(20, Math.min(492, mx))
        S.sy = Math.max(28, Math.min(HORIZON - 24, (my - 256) * aspw + 256))
      }
      // aging is ambient (full cycle ~70s); CLICKING makes time race (~7s)
      S.phase = (S.phase + pdt / (md ? 7 : 70)) % 1
      S.glow = md ? 1 : Math.max(0, S.glow - 1.5 * pdt)

      const moonness = 0.5 - 0.5 * Math.cos(2 * Math.PI * S.phase)
      wd0.music_mod = { brightness: 1 - moonness * 0.72 }

      // the secret: hover the moon's actual reflection on the lake
      const pyRaw = (typeof my === 'number') ? (my - 256) * aspw + 256 : -999
      const refY = 424 + (424 - S.sy) / 1.9
      const hov = moonness > 0.5 && refY < 512 && pyRaw > refY - 22 && pyRaw < refY + 26 ? 1 : 0
      S.gold = (S.gold || 0) + (hov - (S.gold || 0)) * Math.min(1, pdt * 5)
      if (typeof window !== 'undefined') {
        if (hov && !S.capd) { S.capd = true; window.dispatchEvent(new CustomEvent('cafe:caption', { detail: { text: 'the moon invites you · click', kind: 'hint' } })) }
        if (!hov) S.capd = false
        if (hov && md && !S.pmd) { sim.completeChapter(); HX.capd = ''; window.dispatchEvent(new CustomEvent('cafe:caption', { detail: { text: 'CHAPTER II \u2014 THE DROWNED MOON \u00b7 the world under the lake', kind: 'tuned' } })) }
      }
      // ── the six stones, the tree, and seven chapter-door blossoms — KEPT for the scene ──
      if (!wd.__grove || wd.__grove.v !== 3) {
        let sv = null
        try { sv = JSON.parse(localStorage.getItem('cc-helios-grove') || 'null') } catch (e) {}
        const base = { v: 3, lit: [0, 0, 0, 0, 0, 0], started: 0, grow: 0,
                       op: [0, 0, 0, 0, 0, 0, 0], buds: [0, 0, 0, 0, 0, 0, 0] }
        if (sv && (sv.v === 1 || sv.v === 2)) {
          base.lit = sv.lit || base.lit; base.started = sv.started || 0; base.grow = sv.grow || 0
          if (sv.kind) { for (let i = 0; i < 7; i++) if (sv.kind[i] > 0) { base.op[i] = 1; base.buds[i] = 1 } }
          sv = base
        }
        wd.__grove = (sv && sv.v === 3) ? Object.assign(base, sv) : base
        wd.__grove.v = 3
      }
      const G = wd.__grove
      const STONES = [[58, 372], [140, 394], [212, 408], [300, 408], [372, 394], [454, 372]]
      const BUDS_W = [[110, 262], [156, 190], [216, 148], [284, 144], [346, 178], [398, 248], [256, 118]]
      const CHAPTERS = [
        'CHAPTER I \u2014 return to the valley',
        'CHAPTER II \u2014 unwritten',
        'CHAPTER III \u2014 unwritten',
        'CHAPTER IV \u2014 unwritten',
        'CHAPTER V \u2014 unwritten',
        'CHAPTER VI \u2014 unwritten',
        'CHAPTER VII \u2014 unwritten']
      let allLit = true
      for (let i = 0; i < 6; i++) {
        if (G.lit[i] < 1) {
          const dd = Math.hypot(S.sx - STONES[i][0], S.sy - STONES[i][1])
          if (dd < 110) { G.lit[i] = Math.min(1, G.lit[i] + pdt / 3.5); if (G.lit[i] >= 1) G.dirty = 1 }
          if (G.lit[i] < 1) allLit = false
        }
      }
      G.cue = (allLit && !G.started) ? Math.min(1, (G.cue || 0) + pdt * 2) : Math.max(0, (G.cue || 0) - pdt * 2)
      if (allLit && !G.started && !G.hinted && typeof window !== 'undefined') {
        G.hinted = 1
        window.dispatchEvent(new CustomEvent('cafe:caption', { detail: { text: 'the six stones are lit \u00b7 click to wake the tree', kind: 'hint' } }))
      }
      const click = md && !S.pmd && !hov
      if (sim.trigger('ch1_tree', allLit)) {
        G.started = 1; G.dirty = 1
        wd.__play_sound = [
          { frequency: 110, duration: 0.8, volume: 0.35, type: 'sine' },
          { frequency: 440, duration: 0.5, volume: 0.25, type: 'triangle' },
        ]
      }
      if (G.started && G.grow < 1) { G.grow = Math.min(1, G.grow + pdt / 50); if (G.grow >= 1) G.dirty = 1 }

      // blossoms: bloom animation
      for (let i = 0; i < 7; i++) {
        if (G.op[i] > 0 && G.buds[i] < 1) G.buds[i] = Math.min(1, G.buds[i] + pdt * 1.3)
      }
      // hover indicator: nearest blossom under the cursor names its chapter
      G.hover = -1
      if (G.grow >= 0.97 && typeof mx === 'number' && !G.veiling) {
        for (let i = 0; i < 7; i++) {
          if (Math.hypot(mx - BUDS_W[i][0], my - BUDS_W[i][1]) < 24) { G.hover = i; break }
        }
      }
      if (G.hover !== (G.lastHover === undefined ? -1 : G.lastHover)) {
        if (G.hover >= 0 && typeof window !== 'undefined') {
          const label = G.op[G.hover] ? CHAPTERS[G.hover] : CHAPTERS[G.hover] + ' \u00b7 click to open'
          window.dispatchEvent(new CustomEvent('cafe:caption', { detail: { text: label, kind: 'hint' } }))
        }
        G.lastHover = G.hover
      }
      // clicks: first opens the blossom, the second walks through its door
      if (click && G.hover >= 0 && !G.veiling) {
        const i = G.hover
        if (!G.op[i]) {
          G.op[i] = 1; G.dirty = 1
          wd.__play_sound = { frequency: 500 + i * 55, duration: 0.4, volume: 0.3, type: 'sine' }
        } else if (i === 0) {
          // the return door: back to CHAPTER I — the valley begins again
          G.veiling = 1
          wd.__play_sound = [{ frequency: 300, duration: 0.6, volume: 0.3, type: 'sine' },
                              { frequency: 150, duration: 0.9, volume: 0.3, type: 'sine' }]
        } else if (typeof window !== 'undefined') {
          window.dispatchEvent(new CustomEvent('cafe:caption', { detail: { text: CHAPTERS[i] + ' \u00b7 this door is not yet written', kind: 'hint' } }))
          wd.__play_sound = { frequency: 240, duration: 0.3, volume: 0.25, type: 'triangle' }
        }
      }
      // the veil carries the return: fade to black, begin again, fade back
      if (G.veiling === 1) {
        G.veil = Math.min(1, (G.veil || 0) + pdt * 0.8)
        if (G.veil >= 1) {
          G.lit = [0, 0, 0, 0, 0, 0]; G.started = 0; G.grow = 0
          G.op = [0, 0, 0, 0, 0, 0, 0]; G.buds = [0, 0, 0, 0, 0, 0, 0]
          G.cue = 0; G.hinted = 0; G.dirty = 1; G.veiling = 2
        }
      } else if (G.veiling === 2) {
        G.veil = Math.max(0, G.veil - pdt * 0.5)
        if (G.veil <= 0) G.veiling = 0
      }
      G.saveT = (G.saveT || 0) + pdt
      if (G.dirty || G.saveT > 5) {
        G.saveT = 0; G.dirty = 0
        try { localStorage.setItem('cc-helios-grove', JSON.stringify({ v: 3,
          lit: G.lit.map(x => Math.round(x * 100) / 100), started: G.started,
          grow: Math.round(G.grow * 100) / 100, op: G.op,
          buds: G.buds.map(x => Math.round(x * 100) / 100) })) } catch (e) {}
      }
