        col = mix(col, fc, fm);
        col = mix(col, cc * 1.6, smoothstep(3.5, 1.0, pol2.x) * prog * budsOn);
        col += cc * exp(-pol2.x * 0.10) * prog * 0.22 * budsOn;
        alpha = max(alpha, fm);
      }
      // hover indicator: a slow-breathing ring names the door
      if (hovered) {
        let ring = smoothstep(2.2, 0.8, abs(length(lq) - (14.0 + sin(t * 2.2) * 1.5)));
        col += vec3f(0.7, 1.6, 1.9) * ring * 0.9;
        col += vec3f(0.7, 1.6, 1.9) * exp(-length(lq) * 0.09) * 0.25;
        alpha = max(alpha, ring * 0.8);
      }
    }
  }

  if (veil > 0.01) {
    col = mix(col, vec3f(0.0), veil);
    alpha = max(alpha, veil);
  }
  return vec4f(col, alpha);
}

fn hx_seg(p: vec2f, a: vec2f, b: vec2f) -> f32 {
  let pa = p - a;
  let ba = b - a;
  let h = clamp(dot(pa, ba) / max(dot(ba, ba), 1e-6), 0.0, 1.0);
  return length(pa - ba * h);
}

fn hx_moon(rel: vec2f, r: f32, ph: f32) -> f32 {
  let d = length(rel);
  let disc = smoothstep(r, r * 0.9, d);
  let bc = vec2f(cos(6.2831853 * ph), sin(6.2831853 * ph)) * r * 0.72;
  let bite = smoothstep(r * 0.98, r * 0.84, length(rel - bc));
  return disc * (1.0 - bite * 0.93);
}

fn hx_star_pos(i: i32) -> vec2f {
  if (i == 0) { return vec2f(0.00, 0.46); }
  if (i == 1) { return vec2f(-0.11, 0.28); }
  if (i == 2) { return vec2f(0.00, 0.11); }
  if (i == 3) { return vec2f(0.04, -0.10); }
  if (i == 4) { return vec2f(0.00, -0.25); }
  if (i == 5) { return vec2f(0.27, -0.30); }
  return vec2f(0.40, -0.52);
}
fn hx_edge(e: i32) -> vec2f {   // (from, to) star indices per required edge
  if (e == 0) { return vec2f(0.0, 1.0); }
  if (e == 1) { return vec2f(1.0, 2.0); }
  if (e == 2) { return vec2f(2.0, 3.0); }
  if (e == 3) { return vec2f(3.0, 4.0); }
  if (e == 4) { return vec2f(3.0, 5.0); }
  return vec2f(5.0, 6.0);
}

fn visual_helios_chapters(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let act = uni(24);
  if (act < 1.5) { return vec4f(0.0); }
  let t = time;
  let mc = vec2f(uni(0), uni(1));

  // ════ CHAPTER II — THE DROWNED MOON ════
  if (act < 2.5) {
    let ph = uni(2);
    let nvy = clamp(uv.y, -1.3, 1.3);
    var col = mix(vec3f(0.010, 0.018, 0.038), vec3f(0.030, 0.055, 0.095), 0.5 - 0.5 * nvy);
    let ca = sin(uv.x * 9.0 + sin(nvy * 5.0 + t * 0.4) * 1.5 + t * 0.5);
    col += vec3f(0.028, 0.05, 0.07) * (0.5 + 0.5 * ca) * 0.5;
    let sp = uv * 14.0 + vec2f(sin(t * 0.2 + nvy * 2.0) * 0.05, 0.0);
    let sh = hash21(floor(sp));
    if (sh > 0.972) {
      col += vec3f(0.35, 0.45, 0.65) * smoothstep(0.2, 0.03, length(fract(sp) - 0.5)) * (0.4 + 0.4 * sin(t * 1.5 + sh * 40.0));
    }
    let bp = vec2f(uv.x * 10.0, nvy * 6.0 - t * 0.35);
    let bh = hash21(floor(bp));
    if (bh > 0.955) {
      col += vec3f(0.08, 0.13, 0.17) * smoothstep(0.16, 0.02, length(fract(bp) - 0.5));
    }
    let R = 0.68;
    for (var i = 0; i < 6; i++) {
      let fi = f32(i);
      let a = 6.2831853 * fi / 6.0 - 1.5707963;
      let c = vec2f(cos(a), sin(a)) * R;
      let rel = uv - c;
      if (abs(rel.x) < 0.22 && abs(rel.y) < 0.22) {
        let lit = clamp(uni(4 + i), 0.0, 1.0);
        let stone = hx_moon(rel, 0.075, fi / 6.0);
        let scol = mix(vec3f(0.15, 0.17, 0.23), vec3f(1.35, 1.30, 1.05), lit);
        col = mix(col, scol, stone * (0.4 + 0.6 * lit));
        col += vec3f(0.05, 0.06, 0.09) * exp(-dot(rel, rel) * 90.0) * (1.0 - lit);
        let dp = abs(fract(ph - fi / 6.0 + 0.5) - 0.5);
        let phMatch = smoothstep(0.085, 0.03, dp) * (1.0 - lit);
        col += vec3f(1.0, 0.72, 0.28) * exp(-pow((length(rel) - 0.085) * 26.0, 2.0)) * phMatch * (0.6 + 0.4 * sin(t * 5.0));
        col += vec3f(0.85, 0.85, 0.6) * exp(-dot(rel, rel) * 150.0) * lit * 0.9;
      }
    }
    // the moon-tree: the door down to CHAPTER III
    let wt = clamp(uni(11), 0.0, 1.0);
    if (wt > 0.005) {
      let g1 = clamp(wt * 3.0, 0.0, 1.0);
      let g2 = clamp(wt * 3.0 - 1.0, 0.0, 1.0);
      let g3 = clamp(wt * 3.0 - 2.0, 0.0, 1.0);
      let p0 = vec2f(0.0, 0.42);
      let p1 = p0 + vec2f(-0.03, -0.20) * g1;
      let p2 = p1 + vec2f(0.05, -0.19) * g2;
      let p3 = p2 + vec2f(-0.02, -0.16) * g3;
      var td = hx_seg(uv, p0, p1) - 0.022 * (0.6 + 0.4 * g1);
      td = min(td, hx_seg(uv, p1, p2) - 0.016);
      td = min(td, hx_seg(uv, p2, p3) - 0.011);
      for (var bi = 0; bi < 5; bi++) {
        let fb = f32(bi);
        let gb = clamp(wt * 4.0 - 2.2 - fb * 0.25, 0.0, 1.0);
        if (gb > 0.01) {
          let root = mix(p2, p3, 0.2 + fb * 0.2);
          let ang = -1.5707963 + (fb - 2.0) * 0.55 + sin(t * 0.4 + fb) * 0.04;
          let tip = root + vec2f(cos(ang), sin(ang)) * (0.14 + fb * 0.014) * gb;
          td = min(td, hx_seg(uv, root, tip) - 0.006);
          col += vec3f(1.15, 1.10, 0.75) * exp(-dot(uv - tip, uv - tip) * 900.0) * gb * (0.8 + 0.3 * sin(t * 2.0 + fb * 2.1));
          col += vec3f(0.55, 0.60, 0.45) * exp(-dot(uv - tip, uv - tip) * 120.0) * gb * 0.35;
        }
      }
      if (td < 0.0) { col = mix(vec3f(0.72, 0.68, 0.58), vec3f(0.35, 0.30, 0.24), clamp((uv.y - p2.y) * 2.0, 0.0, 1.0)); }
      col += vec3f(1.0, 0.85, 0.45) * exp(-dot(uv - p3, uv - p3) * 9.0) * wt * 0.30;
      col += vec3f(0.9, 0.75, 0.35) * wt * (0.035 + 0.03 * sin(t * 2.1));
    }
    // the drowned moon you carry
    let mr = uv - mc;
    let held = hx_moon(mr, 0.055, ph);
    col = mix(col, vec3f(1.55, 1.55, 1.35), held);
    col += vec3f(0.45, 0.5, 0.68) * exp(-dot(mr, mr) * 55.0) * (0.45 + 0.4 * uni(3));
    col *= 1.0 - 0.4 * pow(length(vec2f(uv.x, nvy)) * 0.72, 3.0);
    if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
    return vec4f(clamp(col, vec3f(0.0), vec3f(30.0)), 1.0);
  }

  // ════ CHAPTER III — THE BEARER: write yourself into the sky ════
  // ════ CHAPTER IV — THE FIRST LIGHT ════
  if (act > 3.5) {
    let life = clamp(uni(2), 0.0, 1.0);
    let held = uni(3);
    let ig = clamp(uni(4), 0.0, 1.0);
    let mm = uv - mc;
    let dd = length(mm);
    let ang = atan2(mm.y, mm.x);
    var col = vec3f(0.004, 0.006, 0.014);
    let dsp = uv * 12.0 + vec2f(0.0, t * 0.02);
    let dh = hash21(floor(dsp));
    if (dh > 0.984) { col += vec3f(0.12, 0.14, 0.22) * smoothstep(0.2, 0.03, length(fract(dsp) - 0.5)) * (0.3 + 0.3 * sin(t + dh * 40.0)); }
    let claw = fbm3(vec2f(ang * 2.2 + 4.0, t * 0.13));
    let bite = (1.0 - life) * (1.0 - ig) * smoothstep(0.3, 0.9, claw);
    let radius = (0.09 + 0.34 * life) * (1.0 - bite * 0.75);
    let warm = mix(vec3f(1.1, 0.72, 0.36), vec3f(1.5, 1.15, 0.7), life);
    let halo = smoothstep(radius, radius * 0.25, dd);
    col += warm * halo * (0.35 + 0.75 * life);
    col += vec3f(1.7, 1.35, 0.9) * exp(-dd * dd / (0.0004 + 0.006 * life)) * (0.7 + 0.6 * life);
    col -= vec3f(0.006, 0.006, 0.012) * smoothstep(radius * 1.6, radius, dd) * bite * 3.0;
    col = max(col, vec3f(0.001, 0.002, 0.006));
    if (life > 0.35) {
      for (var k = 0; k < 3; k = k + 1) {
        let ka = t * 0.6 + f32(k) * 2.094;
        let ep = mc + vec2f(cos(ka), sin(ka)) * radius * 0.7;
        col += vec3f(1.3, 0.9, 0.5) * exp(-dot(uv - ep, uv - ep) * 1400.0) * (life - 0.35) * 1.3;
      }
    }
    if (held > 0.5) {
      let ring = abs(dd - fract(t * 0.8) * radius * 1.4);
      col += warm * smoothstep(0.015, 0.0, ring) * 0.35 * (0.4 + life);
    }
    if (ig > 0.001) {
      let sr = 0.05 + 0.9 * ig * ig;
      col += vec3f(1.9, 1.5, 0.9) * exp(-dd * dd / (sr * sr)) * (0.6 + ig);
      col += vec3f(1.3, 0.95, 0.55) * ig * (0.12 + 0.08 * sin(t * 1.6));
      let rays = 0.5 + 0.5 * sin(ang * 9.0 + t * 0.4);
      col += warm * rays * smoothstep(0.7, 0.05, dd) * ig * 0.18;
      if (ig > 0.97) {
        let dp2 = uv - vec2f(0.0, 0.62);
        let door = smoothstep(0.16, 0.12, abs(dp2.x)) * smoothstep(0.12, 0.09, abs(dp2.y));
        col += vec3f(1.0, 0.9, 0.6) * door * (0.4 + 0.12 * sin(t * 2.0));
      }
    }
    col *= 1.0 - 0.42 * pow(length(uv) * 0.72, 3.0);
    if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
    return vec4f(clamp(col, vec3f(0.0), vec3f(30.0)), 1.0);
  }

  let won = uni(10);
  let bloom = clamp(uni(11), 0.0, 1.0);
  var col = mix(vec3f(0.004, 0.006, 0.018), vec3f(0.014, 0.018, 0.045), 0.5 - 0.5 * uv.y);
  // the ordinary stars, humble
  let sp = uv * 15.0;
  let sh = hash21(floor(sp));
  if (sh > 0.976) {
    col += vec3f(0.5, 0.55, 0.75) * smoothstep(0.2, 0.03, length(fract(sp) - 0.5)) * (0.3 + 0.35 * sin(t * 1.1 + sh * 47.0));
  }

  // the lit threads of the figure
  for (var e = 0; e < 6; e++) {
    let el = clamp(uni(4 + e), 0.0, 1.0);
    if (el > 0.01) {
      let pr = hx_edge(e);
      let a = hx_star_pos(i32(pr.x));
      let b = hx_star_pos(i32(pr.y));
      let dd = hx_seg(uv, a, b);
      // a pulse walks each finished thread
      let along = clamp(dot(uv - a, b - a) / max(dot(b - a, b - a), 1e-5), 0.0, 1.0);
      let pulse = exp(-pow((along - fract(t * 0.23 + f32(e) * 0.17)) * 6.0, 2.0));
      col += vec3f(1.0, 0.92, 0.62) * exp(-dd * 90.0) * el * (0.5 + 0.35 * pulse + bloom * 0.5);
    }
  }

  // the drag in progress: a thread from the held star to your hand
  if (uni(12) > 0.5) {
    let a = vec2f(uni(2), uni(3));
    let dd = hx_seg(uv, a, mc);
    col += vec3f(0.8, 0.85, 1.0) * exp(-dd * 110.0) * (0.35 + 0.15 * sin(t * 6.0));
  }

  // the seven story-stars, brighter than the sky's own
  for (var i = 0; i < 7; i++) {
    let c = hx_star_pos(i);
    let d = length(uv - c);
    let tw = 0.7 + 0.3 * sin(t * 1.7 + f32(i) * 2.3);
    var sc = vec3f(0.95, 0.95, 1.05);
    if (i == 6) { sc = vec3f(1.2, 1.0, 0.55); }   // the light he carries
    col += sc * exp(-d * d * 2200.0) * (1.1 + bloom) * tw;
    col += sc * exp(-d * 26.0) * 0.10 * (1.0 + bloom * 1.6);
  }

  // complete: the Bearer blazes, and a door of the same light opens below
  if (bloom > 0.003) {
    col += vec3f(0.35, 0.30, 0.18) * bloom * (0.10 + 0.05 * sin(t * 0.8));
    let dp = uv - vec2f(0.0, 0.64);
    let door = smoothstep(0.15, 0.12, abs(dp.x)) * smoothstep(0.12, 0.09, abs(dp.y));
    col += vec3f(1.0, 0.9, 0.6) * door * bloom * (0.4 + 0.1 * sin(t * 2.0));
  }

  // your hand — a faint reaching light
  col += vec3f(0.9, 0.9, 1.0) * exp(-dot(uv - mc, uv - mc) * 800.0) * 0.5;

  col *= 1.0 - 0.4 * pow(length(uv) * 0.72, 3.0);
  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(30.0)), 1.0);
}

fn visual_helios_quorum(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  if (abs(uni(24) - 5.0) > 0.5) { return vec4f(0.0); }
  let n = uv * 0.5 + vec2f(0.5);
  var col = mix(vec3f(0.030, 0.018, 0.055), vec3f(0.008, 0.006, 0.018), min(1.0, length(uv) * 0.85));

  // faint filament shimmer in the dark
  let fil = sin(n.x * 38.0 + time * 0.33) * sin(n.y * 31.0 - time * 0.26);
  col += vec3f(0.045, 0.028, 0.085) * smoothstep(0.965, 1.0, fil);

  let pp = vec2f(uni(30), uni(31));
  let tier = uni(32);
  let orbitN = uni(33);
  let settled = uni(34);
  let pulse = uni(35);
  let glow = uni(36);
  let running = uni(37);

  // 25 drifting word-motes
  for (var i: i32 = 0; i < 25; i++) {
    let mx = uni(40 + i * 2);
    if (mx < 0.0) { continue; }
    let my = uni(41 + i * 2);
    let d = max(distance(n, vec2f(mx, my)), 0.004);
    let hue = f32(i) * 0.13;
    let tint = vec3f(0.5) + 0.5 * vec3f(sin(hue), sin(hue + 2.09), sin(hue + 4.18));
    let tw = 0.75 + 0.25 * sin(time * 2.1 + f32(i) * 1.7);
    col += tint * min(0.0009 / (d * d), 1.6) * tw * (1.0 - settled * 0.85);
  }

  // gathered words orbit the player
  for (var k: i32 = 0; k < 5; k++) {
    if (f32(k) >= orbitN) { continue; }
    let a = time * 1.7 + f32(k) * 1.2566;
    let sp = pp + vec2f(cos(a), sin(a)) * 0.034;
    let d = max(distance(n, sp), 0.004);
    col += vec3f(0.92, 0.78, 1.0) * min(0.0004 / (d * d), 1.2);
  }

  // the player node — brighter with every tier climbed
  let pd = max(distance(n, pp), 0.005);
  col += vec3f(0.72, 0.52, 1.0) * min(0.0016 * glow / (pd * pd), 3.0) * running;

  // settled: the field breathes violet around the champion
  let breathe = 0.85 + 0.15 * sin(time * 0.9);
  col += vec3f(0.55, 0.40, 0.95) * settled * 0.5 * exp(-pd * 5.0) * breathe;
  col += vec3f(0.20, 0.12, 0.38) * settled * 0.25 * exp(-length(uv) * 1.4);

  // five tier lamps along the bottom
  for (var t: i32 = 0; t < 5; t++) {
    let lp = vec2f(0.34 + f32(t) * 0.08, 0.94);
    let d = max(distance(n, lp), 0.004);
    let lit = select(0.10, 1.0, f32(t) < tier);
    col += vec3f(0.70, 0.50, 1.0) * lit * min(0.00012 / (d * d), 0.9);
  }

  // tier resolution flash
  col += vec3f(0.45, 0.32, 0.85) * pulse * pulse * 0.10;

  // the risen door, once the field settles
  let dg = max(uni(34) - 0.15, 0.0);
  let dd = max(distance(n, vec2f(0.5, 0.82)), 0.004);
  col += vec3f(1.0, 0.85, 0.55) * dg * min(0.0005 / (dd * dd), 1.4);
  col += vec3f(1.0, 0.9, 0.6) * dg * 0.35 * exp(-abs(n.y - 0.82) * 9.0) * exp(-abs(n.x - 0.5) * 22.0);

  col = col / (col + vec3f(1.0));
  return vec4f(col, 1.0);
}

fn visual_helios_chorus(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  if (abs(uni(24) - 6.0) > 0.5) { return vec4f(0.0); }
  let n = uv * 0.5 + vec2f(0.5);
  let wonT = uni(33);
  // night field warming toward dawn as the chorus completes
  var col = mix(vec3f(0.018, 0.014, 0.045), vec3f(0.010, 0.008, 0.030), min(1.0, length(uv) * 0.9));
  let dawn = mix(vec3f(0.0), vec3f(0.30, 0.16, 0.10), wonT);
  col += dawn * (1.0 - n.y) * 0.9;
  col += vec3f(0.34, 0.14, 0.20) * wonT * exp(-abs(n.y - 0.30) * 5.0) * 0.6;

  let pp = vec2f(uni(30), uni(31));
  let running = uni(34);

  // six pillars on the ring — they sing when lit
  for (var b: i32 = 0; b < 6; b++) {
    let ba = 6.28318 * f32(b) / 6.0 - 1.5708;
    let bp = vec2f(0.5 + cos(ba) * 0.336, 0.5 + sin(ba) * 0.336);
    let lit = uni(35 + b);
    let d = max(distance(n, bp), 0.004);
    let base = vec3f(0.35, 0.30, 0.55);
    let song = vec3f(1.0, 0.78, 0.42);
    col += mix(base, song, lit) * min(0.00035 / (d * d), 1.6) * (0.25 + lit);
    // a soft column of light rises from a singing pillar
    col += song * lit * 0.5 * exp(-abs(n.x - bp.x) * 30.0) * smoothstep(bp.y + 0.02, bp.y - 0.30, n.y);
  }

  // the flock — twelve gold words trailing the light
  for (var i: i32 = 0; i < 12; i++) {
    let mx = uni(42 + i * 2);
    let my = uni(43 + i * 2);
    let d = max(distance(n, vec2f(mx, my)), 0.004);
    let tw = 0.7 + 0.3 * sin(time * 2.3 + f32(i) * 2.1);
    col += vec3f(1.0, 0.82, 0.45) * min(0.0006 / (d * d), 1.5) * tw;
  }

  // the champion's light — warm now, no longer hunting
  let pd = max(distance(n, pp), 0.005);
  col += vec3f(1.0, 0.92, 0.75) * min(0.0016 / (pd * pd), 3.0) * running;

  // dawn door home, once the chorus stands
  let dg = max(wonT - 0.5, 0.0) * 2.0;
  let dd = max(distance(n, vec2f(0.5, 0.82)), 0.004);
  col += vec3f(1.0, 0.88, 0.6) * dg * min(0.0005 / (dd * dd), 1.4);

  col = col / (col + vec3f(1.0));
  return vec4f(col, 1.0);
}
